mapper.select:
SELECT
    COALESCE(SUM(p.total_charge), 0) AS totalRevenue,
    /* 평균 객실 이용률 */
    COALESCE(ROUND(COUNT(CASE WHEN r.status IN ('In','Out') THEN 1 END)/ COUNT(*) * 100, 2), 0) AS avgOccupancy,
    /* 체크인 건수 */
    COUNT(CASE WHEN r.status IN ('In','Out') THEN 1 END) AS totalCheckIn
FROM reservations r LEFT JOIN payments p ON r.idx = p.idx
WHERE r.checkin_date BETWEEN #{startDate} AND #{endDate} AND r.status != 'Cancelled';

SELECT
    COALESCE(SUM(p.total_charge), 0) AS totalRevenue,
    /* 지난달 객실 이용률 */
    COALESCE(ROUND(COUNT(CASE WHEN r.status IN ('In','Out') THEN 1 END) / COUNT(*) * 100, 2), 0) AS avgOccupancy,
    /* 지난달 체크인 건수 */
    COUNT(CASE WHEN r.status IN ('In','Out') THEN 1 END) AS totalCheckIn
FROM reservations r LEFT JOIN payments p ON r.idx = p.idx
WHERE r.checkin_date BETWEEN DATE_FORMAT(DATE_SUB(CURDATE(), INTERVAL 1 MONTH), '%Y-%m-01') AND LAST_DAY(DATE_SUB(CURDATE(), INTERVAL 1 MONTH)) AND r.status != 'Cancelled';

SELECT
    rm.room_type AS label,
    ROUND(COUNT(CASE WHEN r.status IN ('In','Out') THEN 1 END) / COUNT(*) * 100, 2) AS rate
FROM room_master rm LEFT JOIN reservations r ON rm.room_no = r.room_no AND r.checkin_date BETWEEN #{startDate} AND #{endDate}
GROUP BY rm.room_type;
